struct Edge {
	int u, v, w;
};
void solve(int CASE)
{
	int n, m, q; cin >> n >> m >> q;
	var e = vector<Edge>(m + 1);
	fa(i, 1, m) {
		cin >> e[i].u >> e[i].v;
		e[i].w = i;
	}

	// 建树
	int nn = 2 * n - 1;
	var s = vector<int>(nn + 1);
	fa(i, 1, nn)s[i] = i;
	var find = [&](var find, int x)->int {
		if (s[x] == x)return x;
		return s[x] = find(find, s[x]);
		};
	var g = vector<vector<int>>(nn + 1);
	var val = vector<int>(nn + 1);
	var p = Vec2<int>(nn + 1, 31);
	int now = n;
	fa(i, 1, m) {
		const var& [u, v, w] = e[i];
		int e1 = find(find, u);
		int e2 = find(find, v);
		if (e1 != e2) {
			val[++now] = w;
			g[now].pb(e1), g[now].pb(e2);
			s[e1] = now, s[e2] = now;
			p[e1][0] = now, p[e2][0] = now;
		}
	}
	fa(j, 1, 30)fa(i, 1, nn)p[i][j] = p[p[i][j - 1]][j - 1];

	// 计算深度和 dfs 序
	int timer = 0;
	var in = vector<int>(nn + 1);
	var out = vector<int>(nn + 1);
	var rnk = vector<int>(nn + 1);
	var dep = vector<int>(nn + 1);
	var dfs = [&](var dfs, int now, int fa)->void {
		in[now] = ++timer;
		rnk[timer] = now;
		dep[now] = dep[fa] + 1;
		for (int to : g[now]) {
			if (to == fa)continue;
			dfs(dfs, to, now);
		}
		out[now] = timer;
		};
	dfs(dfs, now, 0);

	var stmx = ST<int>(in, ST<int>::_max);
	var stmn = ST<int>(in, ST<int>::_min);
	var lca = [&](int x, int y)->int {
		if (dep[x] < dep[y])swap(x, y);
		fb(i, 30, 0)if (dep[x] - (1 << i) >= dep[y])x = p[x][i];
		if (x == y)return x;
		fb(i, 30, 0)if (p[x][i] != p[y][i])x = p[x][i], y = p[y][i];
		return p[x][0];
		};

	while (q--) {
		int l, r; cin >> l >> r;
		int x = rnk[stmx.queryMax(l, r)]; // 区间 dfs 序最大
		int y = rnk[stmn.queryMin(l, r)]; // 区间 dfs 序最小
		cout << val[lca(x, y)] << ' ';
	}cout << endl;
	return;
}
